[x-cloak] { display: none !important; }

/* ============================================================
   ANNOTATION LAYER — all classes scoped with .anno- prefix
   ============================================================ */

/* Toggle button — fixed bottom-right */
.anno-toggle {
  position: fixed;
  bottom: 24px;
  right: 24px;
  z-index: 9000;
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 8px 16px;
  background: #ffffff;
  border: 1.5px solid #d1d5db;
  border-radius: 8px;
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  font-size: 13px;
  font-weight: 500;
  color: #374151;
  cursor: pointer;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.10);
  transition: background 0.15s, border-color 0.15s, color 0.15s, box-shadow 0.15s;
  user-select: none;
}
.anno-toggle:hover {
  background: #f3f4f6;
  border-color: #9ca3af;
}
.anno-toggle.anno-toggle--active {
  background: #2563eb;
  border-color: #1d4ed8;
  color: #ffffff;
  box-shadow: 0 2px 12px rgba(37, 99, 235, 0.30);
}
.anno-toggle.anno-toggle--active:hover {
  background: #1d4ed8;
  border-color: #1e40af;
}
.anno-toggle__icon {
  width: 16px;
  height: 16px;
  flex-shrink: 0;
}
.anno-toggle__count {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 18px;
  height: 18px;
  padding: 0 5px;
  background: rgba(255, 255, 255, 0.25);
  border-radius: 999px;
  font-size: 11px;
  font-weight: 600;
  line-height: 1;
}

/* Hover tooltip on [data-name] elements while annotation mode is active */
.anno-hover-tooltip {
  position: fixed;
  z-index: 9100;
  pointer-events: none;
  padding: 4px 8px;
  background: #1e293b;
  color: #f8fafc;
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  font-size: 11px;
  font-weight: 500;
  border-radius: 4px;
  white-space: nowrap;
  box-shadow: 0 2px 6px rgba(0, 0, 0, 0.20);
  display: none;
}
.anno-hover-tooltip.anno-hover-tooltip--visible {
  display: block;
}

/* Hover highlight ring — injected via JS as outline on the target element */
.anno-highlight {
  outline: 2px dashed #2563eb !important;
  outline-offset: 2px !important;
}

/* Annotation badges — numbered circles on annotated elements */
.anno-badge {
  position: absolute;
  top: -8px;
  left: -8px;
  z-index: 9050;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 22px;
  height: 22px;
  background: #2563eb;
  color: #ffffff;
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  font-size: 11px;
  font-weight: 700;
  border-radius: 999px;
  border: 2px solid #ffffff;
  box-shadow: 0 1px 4px rgba(0, 0, 0, 0.20);
  cursor: pointer;
  pointer-events: all;
  transition: transform 0.1s, background 0.1s;
}
.anno-badge:hover {
  transform: scale(1.15);
  background: #1d4ed8;
}

/* Popover — anchored to clicked element */
.anno-popover {
  position: fixed;
  z-index: 9200;
  width: 280px;
  background: #ffffff;
  border: 1px solid #e5e7eb;
  border-radius: 10px;
  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.14);
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  overflow: hidden;
}
.anno-popover__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 14px 8px;
  border-bottom: 1px solid #f3f4f6;
}
.anno-popover__target {
  font-size: 12px;
  font-weight: 600;
  color: #111827;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  max-width: 200px;
}
.anno-popover__close {
  width: 24px;
  height: 24px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: none;
  border: none;
  border-radius: 4px;
  cursor: pointer;
  color: #6b7280;
  font-size: 16px;
  line-height: 1;
  padding: 0;
  flex-shrink: 0;
}
.anno-popover__close:hover {
  background: #f3f4f6;
  color: #374151;
}
.anno-popover__body {
  padding: 10px 14px 12px;
  display: flex;
  flex-direction: column;
  gap: 10px;
}
.anno-popover__label {
  font-size: 11px;
  font-weight: 600;
  color: #6b7280;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin-bottom: 4px;
}
.anno-popover__textarea {
  width: 100%;
  min-height: 72px;
  padding: 8px 10px;
  background: #f9fafb;
  border: 1px solid #e5e7eb;
  border-radius: 6px;
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  font-size: 13px;
  color: #111827;
  resize: vertical;
  outline: none;
  transition: border-color 0.15s;
  box-sizing: border-box;
}
.anno-popover__textarea:focus {
  border-color: #2563eb;
  background: #ffffff;
}
.anno-popover__textarea::placeholder {
  color: #9ca3af;
}

/* Severity picker */
.anno-severity {
  display: flex;
  gap: 6px;
}
.anno-severity__btn {
  flex: 1;
  padding: 5px 8px;
  border-radius: 6px;
  border: 1.5px solid #e5e7eb;
  background: #f9fafb;
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  font-size: 12px;
  font-weight: 500;
  color: #6b7280;
  cursor: pointer;
  text-align: center;
  transition: background 0.12s, border-color 0.12s, color 0.12s;
}
.anno-severity__btn:hover {
  background: #f3f4f6;
  border-color: #d1d5db;
  color: #374151;
}
/* Active states: change=blue, note=green */
.anno-severity__btn--change.anno-severity__btn--active {
  background: #eff6ff;
  border-color: #2563eb;
  color: #1d4ed8;
}
.anno-severity__btn--note.anno-severity__btn--active {
  background: #f0fdf4;
  border-color: #22c55e;
  color: #16a34a;
}

/* Popover action row */
.anno-popover__actions {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 8px 14px 12px;
  border-top: 1px solid #f3f4f6;
}
.anno-popover__btn {
  padding: 6px 14px;
  border-radius: 6px;
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  font-size: 13px;
  font-weight: 500;
  cursor: pointer;
  border: none;
  transition: background 0.12s;
}
.anno-popover__btn--save {
  background: #2563eb;
  color: #ffffff;
}
.anno-popover__btn--save:hover {
  background: #1d4ed8;
}
.anno-popover__btn--save:disabled {
  background: #93c5fd;
  cursor: not-allowed;
}
.anno-popover__btn--cancel {
  background: #f3f4f6;
  color: #374151;
}
.anno-popover__btn--cancel:hover {
  background: #e5e7eb;
}
.anno-popover__btn--delete {
  margin-left: auto;
  background: none;
  color: #ef4444;
  padding: 6px 8px;
  border-radius: 6px;
}
.anno-popover__btn--delete:hover {
  background: #fef2f2;
}

/* Export panel — fixed above toggle button */
.anno-panel {
  position: fixed;
  bottom: 80px;
  right: 24px;
  z-index: 9100;
  width: 360px;
  max-height: 480px;
  background: #ffffff;
  border: 1px solid #e5e7eb;
  border-radius: 12px;
  box-shadow: 0 12px 32px rgba(0, 0, 0, 0.14);
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  display: flex;
  flex-direction: column;
  overflow: hidden;
}
.anno-panel__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 12px 16px 10px;
  border-bottom: 1px solid #f3f4f6;
  flex-shrink: 0;
}
.anno-panel__title {
  font-size: 13px;
  font-weight: 700;
  color: #111827;
}
.anno-panel__header-actions {
  display: flex;
  align-items: center;
  gap: 6px;
}
.anno-panel__hbtn {
  padding: 4px 10px;
  border-radius: 6px;
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  font-size: 12px;
  font-weight: 500;
  cursor: pointer;
  border: none;
  transition: background 0.12s;
}
.anno-panel__hbtn--apply {
  background: #16a34a;
  color: #ffffff;
}
.anno-panel__hbtn--apply:hover {
  background: #15803d;
}
.anno-panel__hbtn--apply:disabled {
  background: #86efac;
  cursor: default;
  color: #166534;
}
.anno-panel__hbtn--copy {
  background: #2563eb;
  color: #ffffff;
}
.anno-panel__hbtn--copy:hover {
  background: #1d4ed8;
}
.anno-panel__hbtn--clear {
  background: #f3f4f6;
  color: #ef4444;
}
.anno-panel__hbtn--clear:hover {
  background: #fef2f2;
}
.anno-panel__hbtn--close {
  background: #f3f4f6;
  color: #374151;
}
.anno-panel__hbtn--close:hover {
  background: #e5e7eb;
}
.anno-panel__list {
  overflow-y: auto;
  flex: 1;
  padding: 8px 0;
}
.anno-panel__empty {
  padding: 24px 16px;
  text-align: center;
  font-size: 13px;
  color: #9ca3af;
}
.anno-panel__item {
  display: flex;
  align-items: flex-start;
  gap: 10px;
  padding: 8px 16px;
  border-bottom: 1px solid #f9fafb;
}
.anno-panel__item:last-child {
  border-bottom: none;
}
.anno-panel__num {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 20px;
  height: 20px;
  background: #2563eb;
  color: #ffffff;
  font-size: 11px;
  font-weight: 700;
  border-radius: 999px;
  flex-shrink: 0;
  margin-top: 1px;
}
.anno-panel__item-body {
  flex: 1;
  min-width: 0;
}
.anno-panel__item-target {
  font-size: 12px;
  font-weight: 600;
  color: #374151;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}
.anno-panel__item-msg {
  font-size: 12px;
  color: #6b7280;
  margin-top: 2px;
  word-break: break-word;
}
.anno-panel__item-sev {
  margin-top: 4px;
  display: inline-block;
  padding: 1px 7px;
  border-radius: 999px;
  font-size: 11px;
  font-weight: 600;
}
.anno-panel__item-sev--change { background: #eff6ff; color: #1d4ed8; }
.anno-panel__item-sev--note   { background: #f0fdf4; color: #16a34a; }
.anno-panel__copy-feedback {
  padding: 6px 16px 8px;
  font-size: 12px;
  color: #16a34a;
  font-weight: 500;
  text-align: center;
  border-top: 1px solid #f3f4f6;
  flex-shrink: 0;
}

