1	  document.addEventListener('alpine:init', () => {
2	    Alpine.data('annotationLayer', () => ({
3	      /** Whether annotation click-to-annotate mode is active */
4	      active: false,
5	
6	      /** All persisted annotations for this page */
7	      annotations: [],
8	
9	      /** Whether the export panel is open */
10	      panelOpen: false,
11	
12	      /** Brief copy-to-clipboard feedback flag */
13	      copyFeedback: false,
14	
15	      /** Whether annotations have been submitted to the server */
16	      submitted: false,
17	
18	      /** Popover state */
19	      popover: {
20	        open: false,
21	        x: 0,
22	        y: 0,
23	        target: '',
24	        message: '',
25	        severity: 'change',
26	        editingId: null,
27	        /** The actual DOM element being annotated */
28	        _el: null,
29	      },
30	
31	      /** localStorage key for this page */
32	      _storageKey: 'anno-' + location.pathname,
33	
34	      /** Injected badge elements keyed by annotation id */
35	      _badges: {},
36	
37	      /** Currently hovered element (for outline/tooltip) */
38	      _hoveredEl: null,
39	
40	      /** Bound event handler references (for cleanup) */
41	      _onDocClick: null,
42	      _onDocMouseover: null,
43	      _onDocMouseout: null,
44	      _onMousemove: null,
45	
46	      // ─────────────────────────────────────────────
47	      // Lifecycle
48	      // ─────────────────────────────────────────────
49	
50	      init() {
51	        this._load();
52	        this.renderBadges();
53	        this._bindHoverHandlers();
54	        this._bindClickCapture();
55	      },
56	
57	      // ─────────────────────────────────────────────
58	      // Mode toggle
59	      // ─────────────────────────────────────────────
60	
61	      toggleMode() {
62	        this.active = !this.active;
63	        if (!this.active) {
64	          this._clearHover();
65	          this.closePopover();
66	        }
67	        document.body.style.cursor = this.active ? 'crosshair' : '';
68	      },
69	
70	      // ─────────────────────────────────────────────
71	      // Popover
72	      // ─────────────────────────────────────────────
73	
74	      openPopover(el) {
75	        const rect = el.getBoundingClientRect();
76	        const vpW = window.innerWidth;
77	        const vpH = window.innerHeight;
78	        const popW = 280;
79	        const popH = 260; // approximate
80	
81	        // Default: appear below-right of element
82	        let x = rect.left;
83	        let y = rect.bottom + 8;
84	
85	        // Flip horizontally if overflowing right edge
86	        if (x + popW > vpW - 16) {
87	          x = Math.max(16, vpW - popW - 16);
88	        }
89	        // Flip vertically if overflowing bottom
90	        if (y + popH > vpH - 16) {
91	          y = Math.max(16, rect.top - popH - 8);
92	        }
93	
94	        this.popover.x = Math.round(x);
95	        this.popover.y = Math.round(y);
96	        this.popover.target = el.dataset.name || el.tagName.toLowerCase();
97	        this.popover._el = el;
98	
99	        // Focus textarea after Alpine re-renders
100	        this.$nextTick(() => {
101	          const ta = document.getElementById('anno-popover-textarea');
102	          if (ta) ta.focus();
103	        });
104	      },
105	
106	      closePopover() {
107	        this.popover.open = false;
108	        this.popover.editingId = null;
109	        this.popover.message = '';
110	        this.popover.severity = 'note';
111	        this.popover._el = null;
112	      },
113	
114	      // ─────────────────────────────────────────────
115	      // CRUD
116	      // ─────────────────────────────────────────────
117	
118	      saveAnnotation() {
119	        const msg = this.popover.message.trim();
120	        if (!msg) return;
121	
122	        if (this.popover.editingId !== null) {
123	          // Update existing
124	          const idx = this.annotations.findIndex(a => a.id === this.popover.editingId);
125	          if (idx !== -1) {
126	            this.annotations[idx].message = msg;
127	            this.annotations[idx].severity = this.popover.severity;
128	          }
129	        } else {
130	          // Create new — store targetIndex to disambiguate duplicate data-name values
131	          const allMatches = document.querySelectorAll(`[data-name="${CSS.escape(this.popover.target)}"]`);
132	          let targetIndex = 0;
133	          allMatches.forEach((el, i) => { if (el === this.popover._el) targetIndex = i; });
134	
135	          this.annotations.push({
136	            id: Date.now() + Math.random(),
137	            target: this.popover.target,
138	            targetIndex: targetIndex,
139	            message: msg,
140	            severity: this.popover.severity,
141	            createdAt: new Date().toISOString(),
142	            _el: this.popover._el,
143	          });
144	        }
145	
146	        this.submitted = false;
147	        this.persist();
148	        this.renderBadges();
149	        this.closePopover();
150	      },
151	
152	      deleteAnnotation(id) {
153	        this.annotations = this.annotations.filter(a => a.id !== id);
154	        this._removeBadge(id);
155	        this.persist();
156	        this.closePopover();
157	      },
158	
159	      clearAll() {
160	        if (!confirm('Clear all annotations for this page?')) return;
161	        this.annotations = [];
162	        Object.keys(this._badges).forEach(id => this._removeBadge(id));
163	        this._badges = {};
164	        this.persist();
165	      },
166	
167	      editAnnotation(a) {
168	        // Re-resolve element (may have been GC'd if DOM changed)
169	        const el = a._el || document.querySelector(`[data-name="${CSS.escape(a.target)}"]`);
170	        this.popover.editingId = a.id;
171	        this.popover.message = a.message;
172	        this.popover.severity = a.severity;
173	        this.popover.target = a.target;
174	        this.popover._el = el;
175	        this.popover.open = true;
176	
177	        if (el) {
178	          this.openPopover(el);
179	          // openPopover resets message/severity — restore after
180	          this.$nextTick(() => {
181	            this.popover.message = a.message;
182	            this.popover.severity = a.severity;
183	            this.popover.editingId = a.id;
184	            const ta = document.getElementById('anno-popover-textarea');
185	            if (ta) ta.focus();
186	          });
187	        }
188	      },
189	
190	      // ─────────────────────────────────────────────
191	      // Persistence
192	      // ─────────────────────────────────────────────
193	
194	      persist() {
195	        try {
196	          const serialisable = this.annotations.map(a => ({
197	            id: a.id,
198	            target: a.target,
199	            targetIndex: a.targetIndex || 0,
200	            message: a.message,
201	            severity: a.severity,
202	            createdAt: a.createdAt,
203	          }));
204	          localStorage.setItem(this._storageKey, JSON.stringify(serialisable));
205	        } catch (e) {
206	          // localStorage may be unavailable (e.g., private browsing with full quota)
207	          console.warn('[annotation-layer] Could not persist to localStorage:', e);
208	        }
209	      },
210	
211	      _load() {
212	        try {
213	          const raw = localStorage.getItem(this._storageKey);
214	          if (raw) {
215	            const parsed = JSON.parse(raw);
